const Q_ACCOUNTS_2016=[{"id": "objective>Accounts>2016>1", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following relate to the profit and loss account of a manufacturing firm? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Administration overhead </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Direct materials </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Work-in-progress </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Direct labour </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A administrative overhead because it does not have a direct relationship with manufacturing process. It is also known as an indirect expenses or overhead.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2016>2", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Balance as per cashbook</td><td style=\"border:1px solid black;text-align:center;\"> 2,970 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">bank charges</td><td style=\"border:1px solid black;text-align:center;\"> 220 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Unpresented cheques</td><td style=\"border:1px solid black;text-align:center;\"> 3,950 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Uncredited cheques</td><td style=\"border:1px solid black;text-align:center;\"> 4,178 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Direct debit by bank</td><td style=\"border:1px solid black;text-align:center;\"> 1,000</td></tr></table></div> <br/> Calculate the adjusted cashbook balance.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦3,750</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,750</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,190</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦4,190</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">To calculate the adjusted cashbook balance.  <br/>  <br/> This will be additional of :  <br/> balance as per cashbook  2970+  Bank charges 220+  Direct debit by bank 1000  <br/>  = ₦ 4,190.</div>", "topic": "BANK RECONCILIATION STATEMENT : PREPARATION OF BANK RECONCILIATION STATEMENT"}, {"id": "objective>Accounts>2016>3", "question": "<div style=\"font-family:Cambria;font-size:17px;\">During the year ended 31st, December 2001, Nuju Enterprises paid rent as follows;  <br/> January 20, ₦ 24,000 for a period of 4 months, <br/> May 16, ₦30,000 for a period of 5 months, <br/> October 15, ₦36,000 for a period of 6 months, <br/> What is the overpaid portion of the rent?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦ 36,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦ 18,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦ 12,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦ 6,000</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">From the question above, per month is #6,000 <br/> Therefore, Oct to Dec = #18,000 and he paid #36,000 <br/> It is assumed that half of the payment have been utilized by 31st December 2001, so the overpayment is ₦ 18,000.</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS"}, {"id": "objective>Accounts>2016>4", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A machine worth ₦15,000 has a useful life of 4 years and an expected disposal value of ₦ 4,000.  Use the straight line method to calculate the total annual depreciation. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦3,570</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,570 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,750 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦3,750 </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate by formular  <br/>  Straight line method of depreciation = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">Cost of asset - Scrap value</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">estimated useful life </span> <br/>  <br/>  = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">15,000 - 4,000</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4 </span> <br/>  <br/> = <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">11,000</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4</span> <br/>  <br/> = 2750 </div>", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION"}, {"id": "objective>Accounts>2016>5", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Departments</td><td style=\"border:1px solid black;text-align:center;\"> Men</td><td style=\"border:1px solid black;text-align:center;\"> Ladies</td><td style=\"border:1px solid black;text-align:center;\"> Children  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> ₦50,000</td><td style=\"border:1px solid black;text-align:center;\"> ₦75,000</td><td style=\"border:1px solid black;text-align:center;\"> ₦75,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Floor space</td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4</span></td><td style=\"border:1px solid black;text-align:center;\"><span style=\"position: relative;left:3px;top:-7px; font-size:15px;\"> 2</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4</span></td><td style=\"border:1px solid black;text-align:center;\"> <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\">1</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">4 </span></td></tr></table></div> <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Heating and lighting</td><td style=\"border:1px solid black;text-align:center;\"> 30,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rent</td><td style=\"border:1px solid black;text-align:center;\"> 60,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Administration and general expenses</td><td style=\"border:1px solid black;text-align:center;\"> 20,000</td></tr></table></div>  <br/> Heating and lighting and rent are to be apportioned based on floor space while administrative and general expenses are given.  <br/>  Determine the amount of heating and lighting expenses to be apportioned to the children's department? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦15,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦7,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦30,000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦7,500</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\">Men</td><td style=\"border:1px solid black;text-align:center;\">Ladies</td><td style=\"border:1px solid black;text-align:center;\"> Children  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">1/4</td><td style=\"border:1px solid black;text-align:center;\"> 2/4</td><td style=\"border:1px solid black;text-align:center;\"> 1/4   <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Heating and lighting</td><td style=\"border:1px solid black;text-align:center;\"> 7,500</td><td style=\"border:1px solid black;text-align:center;\"> 15,000</td><td style=\"border:1px solid black;text-align:center;\"> 7,500 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rent</td><td style=\"border:1px solid black;text-align:center;\"> 15,000</td><td style=\"border:1px solid black;text-align:center;\"> 30,000</td><td style=\"border:1px solid black;text-align:center;\"> 15,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Admin and General Exp.</td><td style=\"border:1px solid black;text-align:center;\"> 5,000</td><td style=\"border:1px solid black;text-align:center;\"> 10,000</td><td style=\"border:1px solid black;text-align:center;\"> 5,000</td></tr></table></div> <br/> Heating and lighting expenses to be apportioned to Children Department = ₦7,500</div>", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES"}, {"id": "objective>Accounts>2016>6", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The financial plan of the government for a year is contained in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gazette </div>", "<div style=\"font-family:Cambria;font-size:17px;\">budget </div>", "<div style=\"font-family:Cambria;font-size:17px;\">vote book </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash analysis book </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Budget is an estimated income and expenses which the government is expected to earn and incurred during a particular financial period usually one year (January to December).</div>", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES"}, {"id": "objective>Accounts>2016>7", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cost of machine was ₦ 100,000 and an estimate salvage value of ₦ 2,000 with a useful life of 14 years.  <br/>  What is the accumulated depreciation for the past 4 years? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦26,000</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦28,000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦72,800 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦72,000 </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost of machine - scrap value/useful = ₦(100,000 - 2000/14)  <br/>  = ₦7,000  <br/>  <br/>  Accumulated depreciation for 4 years = 4 x 7,000  <br/>  = ₦28,000</div>", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION"}, {"id": "objective>Accounts>2016>8", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cost of acquiring fixed assets and bring them into the firm is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Recurrent expenditure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Capital expenditure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Revenue expenditure </div>", "<div style=\"font-family:Cambria;font-size:17px;\">General expenses</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Capital expenditure; money spent by a business or organization on acquiring or maintaining fixed assets, such as land, buildings, and equipment.</div>", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY"}, {"id": "objective>Accounts>2016>9", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Cashbook can also be used as both </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">sales book and ledger account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit note and ledger account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit note ledger account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">daybook and ledger account </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A cashbook is a financial journal that contains all cash receipts and payments, including bank deposits and withdrawals. Entries in the cashbook are then posted into the general ledger. Therefore, it can be used as both a daybook (a daily record of all financial entries) and a ledger account (a record for summarizing all of a company's financial transactions).</div>", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK"}, {"id": "objective>Accounts>2016>10", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The control account is used in facilitating </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">The payment debts and liabilities of the firm </div>", "<div style=\"font-family:Cambria;font-size:17px;\">The location of errors on the various accounts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">assets distribution with respect to income </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Up to date bank transaction </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Control account is also known as general ledger account. Its balance reflects the aggregate balance of related subsidiary ledger accounts and usefully used for location of errors on the various account within the general ledger. </div>", "topic": "CONTROL ACCOUNTS : INTRODUCTION, ADVANTAGES OF CONTROL ACCOUNTS"}, {"id": "objective>Accounts>2016>11", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Working capital is calculated as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">fixed assets plus current assets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">current liabilities plus current assets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">capital less current assets </div>", "<div style=\"font-family:Cambria;font-size:17px;\">current assets less current liabilities </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Working capital is calculated as current assets less current liabilities. This is because working capital represents the short-term liquidity of a company, which is the difference between its short-term assets (current assets) and its short-term liabilities (current liabilities).</div>", "topic": "ACCOUNTING RATIO ( 1) : INTRODUCTION AND USES"}, {"id": "objective>Accounts>2016>12", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The book value of all assets during partnership dissolution are entered in the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">credit side of profit and loss account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit side of cash account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit side of realization account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit side of assets account </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">During the dissolution of a partnership, the book value of all assets is entered on the debit side of the realization account. This is because the realization account is used to record the realization of assets and liabilities. The debit side records the book value of assets while the credit side records the realized value of assets and liabilities.</div>", "topic": "DISSOLUTION OF PARTNERSHIP ACCOUNT : INTRODUCTION AND RULES FOR DISTRIBUTING OF ASSSETS"}, {"id": "objective>Accounts>2016>13", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a department account, where no basis of apportionment exist, apportionment is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">according to material available </div>", "<div style=\"font-family:Cambria;font-size:17px;\">on profit basis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">on equal basis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">according to employee decision </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a department account, where no basis of apportionment exist, apportionment is on equal basis i.e shared equally.</div>", "topic": "DEPARTMENTAL ACCOUNT : METHODS OF APPORTIONMENT OF EXPENSES"}, {"id": "objective>Accounts>2016>14", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following would be disclosed by the trial balance? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">purchases from Audu entered in Audu's account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Error on a purchase invoice </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Overcast of total on sales account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Carriage outwards debited to sales account </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An overcast means the total sales have been recorded higher than they actually are. This would cause the trial balance to show more credit than debit, as sales are a credit account. Therefore, this can be disclosed by the trial balance.</div>", "topic": "TRIAL BALANCE : ERRORS NOT DISCLOSED BY TRIAL BALANCE"}, {"id": "objective>Accounts>2016>15", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The three cash book differs from the two column, in that, the three column has a column for </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">folio </div>", "<div style=\"font-family:Cambria;font-size:17px;\">discount </div>", "<div style=\"font-family:Cambria;font-size:17px;\">bank </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Three column cashbook differs from two column in that three column has a column for discount allowed on the debit side and discount received on the credit side. </div>", "topic": "CASH BOOK : THREE COLUMN CASH BOOK"}, {"id": "objective>Accounts>2016>16", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The cost that does NOT relate directly to the goods manufactured is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">production cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">direct cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">overhead cost </div>", "<div style=\"font-family:Cambria;font-size:17px;\">realized cost </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Cost that does not relate directly to manufacturing process is known as indirect expenses or overhead cost </div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2016>17", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When goods are returned from a branch to the head office, the accounting entries would be to debit the goods sent to branch and credit</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">adjustment account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debtor's account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stock account </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When goods are returned from branch to the head office the account entries are: <br/>  <br/> DR: goods sent to branch account with the cost of the goods <br/>  DR: Branch stock account with the sales value - cost of the goods.  <br/>  CR Branch debtors a/c with the sales value of the goods.</div>", "topic": "BRANCH ACCOUNTING : BRANCH ADJUSTMENT METHOD"}, {"id": "objective>Accounts>2016>18", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The amount of money for a particular purpose by a government organization for its expenditure is the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">surplus </div>", "<div style=\"font-family:Cambria;font-size:17px;\">balance </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deficit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fund </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Fund is the amount set aside for a particular purpose by a government organization for its expenditure.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : ESTIMATES"}, {"id": "objective>Accounts>2016>19", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When goods are sent to the branch at cost plus mark-up, it means that the branch should sell at </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">any price but not below the transfer price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a price that is equal to the mark-up </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost price </div>", "<div style=\"font-family:Cambria;font-size:17px;\">a price above or below the stipulated price </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">When goods are sent to the branch at cost plus mark-up, it means that the branch should sell at any price but not below the transfer price. The transfer price is the total cost of the goods (original cost plus mark-up). Selling below this price would result in a loss for the branch.</div>", "topic": "BRANCH ACCOUNTING : PRICING METHODS"}, {"id": "objective>Accounts>2016>20", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The ratio that gives the indication of the efficacy of a firm's sales with respect to cost of goods sold is a </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">return on capital employed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">net profit margin </div>", "<div style=\"font-family:Cambria;font-size:17px;\">return on equity </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gross profit margin </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The ratio that gives the indication of the efficacy of a firm's sales with respect to cost of goods sold is the gross profit margin. Gross profit margin is a profitability ratio that calculates the percentage of sales that exceed the cost of goods sold. It measures the efficiency of a company using its raw materials and labor during the production process.</div>", "topic": "ACCOUNTING RATIO (2) : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO"}, {"id": "objective>Accounts>2016>21", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the advantage of stock valuation is that, it determines </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">the number of goods to produce </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the goods for sale </div>", "<div style=\"font-family:Cambria;font-size:17px;\">which market to sell the goods </div>", "<div style=\"font-family:Cambria;font-size:17px;\">when to sell certain goods </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Stock valuation is a process of determining the actual amount of stock and also a process of determining the actual market value of the stock it main advantages is that it determines the actual goods meant for sale.</div>", "topic": "STOCK VALUATION : MEANING OF STOCK VALUATION AND METHODS"}, {"id": "objective>Accounts>2016>22", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The general ledger contains </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">real and nominal accounts </div>", "<div style=\"font-family:Cambria;font-size:17px;\">nominal and purchases account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">real and debtors account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">tangible and creditors account </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">General ledger contains the nominal and real accounts. It also contain the sales account, purchases account, returns inwards, returns outwards account etc.</div>", "topic": "THE LEDGER : MEANING AND DIVISION OF LEDGER"}, {"id": "objective>Accounts>2016>23", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In a manufacturing account, the work in-progress at the end of the year is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">added to the cost of goods completed </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stated in the prime cost section </div>", "<div style=\"font-family:Cambria;font-size:17px;\">stated in profit and loss account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">deducted from the cost of goods completed during the year</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Goods which are not finished are known as work-in-progress. The opening balance of work-in-progress is added on to the production cost and the work-in-progress left at the end of the year will need subtracting to give us the cost of the goods completed during the period we are dealing with.</div>", "topic": "MANUFACTURING ACCOUNTS : INTRODUCTION AND PURPOSE"}, {"id": "objective>Accounts>2016>24", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Incomplete Record (extract) <br/> <div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> ₦</td><td style=\"border:1px solid black;text-align:center;\"> ₦  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Sales</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 10 600 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Rent</td><td style=\"border:1px solid black;text-align:center;\"> 200</td><td style=\"border:1px solid black;text-align:center;\"></td></tr></table></div> <br/> Depreciation  of vehicle (cost ₦5,000) 10%  <br/>  Gross profit margin 20%  <br/>  What is the cost of goods sold?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦4,800 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦9,900 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,320 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦8,480 </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross profit margin = 20%  <br/>  <br/> <span style=\"position: relative;left:3px;top:-7px; font-size:15px;\"> 20</span>/<span style=\"position:relative;left:-3px;top:7px;font-size:15px;\">100</span> x 10600 <br/>  <br/>  = 2,120 <br/>   <br/>  Sales = Cost of Goods sold + Gross profit  <br/>  <br/>  10,600 = x + 2,120  <br/>  <br/>  x + 2,120 = 10,600  <br/>  <br/>  x = 10,600 - 2,120  <br/> = ₦8,480 </div>", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : COMPUTATION OF PROFIT"}, {"id": "objective>Accounts>2016>25", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The closing in a petty cashbook was ₦ 2,050 imprest float ₦4,250, stationery expenses ₦550 and postage ₦365. How much was paid for the general expenses? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦1650 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦3,335 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦1,285 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,200</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">₦(550 + 365 + x + 2050) = 4,250 <br/>  <br/>  ₦4,250 = ₦(550 + 365 + x + 2050)  <br/>  <br/>  ₦4,250 = ₦(x + 2,965)  <br/>  <br/>   x = ₦4,250 - 2,965 <br/>  <br/>  x = ₦1,285 </div>", "topic": "PETTY CASH BOOK : MEANING AND IMPORTANCE"}, {"id": "objective>Accounts>2016>26", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The trader's capital in a single system is ascertained by preparing </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">suspense account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">statement of affairs</div>", "<div style=\"font-family:Cambria;font-size:17px;\">appropriation account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">gross profit </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a single entry system, the trader's capital is ascertained by preparing a statement of affairs. A statement of affairs is a financial statement that shows the assets, liabilities, and capital of a business at a particular point in time. It is used in a single entry system because this system does not keep a complete double-entry record of all transactions, so the statement of affairs is used to estimate the capital.</div>", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : STATEMENT OF AFFAIRS"}, {"id": "objective>Accounts>2016>27", "question": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\"></td><td style=\"border:1px solid black;text-align:center;\"> ₦ <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cash balance</td><td style=\"border:1px solid black;text-align:center;\"> 2,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Bank balance</td><td style=\"border:1px solid black;text-align:center;\"> 3,000 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cash sales paid direct into the bank</td><td style=\"border:1px solid black;text-align:center;\"> 500 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">Cash withdrawn from the bank for office use</td><td style=\"border:1px solid black;text-align:center;\"> 900</td></tr></table></div> <br/> Find the cash balance. </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦4,200 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,500 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦5,000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,900 </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"><div style=\"display:block;position:relative;width:100%;\"><table cellpadding=\"4\" cellspacing=\"0\" style=\"position: relative;border-collapse:collapse;\"><tr><td style=\"border:1px solid black;text-align:center;\">Date</td><td style=\"border:1px solid black;text-align:center;\"> particulars</td><td style=\"border:1px solid black;text-align:center;\"> Cash</td><td style=\"border:1px solid black;text-align:center;\"> bank</td><td style=\"border:1px solid black;text-align:center;\"> Date</td><td style=\"border:1px solid black;text-align:center;\"> particular</td><td style=\"border:1px solid black;text-align:center;\"> Cash</td><td style=\"border:1px solid black;text-align:center;\"> bank</td></tr><tr><td style=\"border:1px solid black;text-align:center;\">1/1/</td><td style=\"border:1px solid black;text-align:center;\"> bal. b/d</td><td style=\"border:1px solid black;text-align:center;\"> 2000</td><td style=\"border:1px solid black;text-align:center;\"> 3000</td><td style=\"border:1px solid black;text-align:center;\">4/1/</td><td style=\"border:1px solid black;text-align:center;\"> Cash drawing (C)</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 900 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">2/1/</td><td style=\"border:1px solid black;text-align:center;\"> Cash</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">500</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> bal. c/d</td><td style=\"border:1px solid black;text-align:center;\"> 2,900</td><td style=\"border:1px solid black;text-align:center;\">2,600 <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\">3/1/</td><td style=\"border:1px solid black;text-align:center;\"> bank (C)</td><td style=\"border:1px solid black;text-align:center;\"> 900</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">  <br/> </td></tr><tr><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> 2,900</td><td style=\"border:1px solid black;text-align:center;\">3,500</td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\"> </td><td style=\"border:1px solid black;text-align:center;\">2900</td><td style=\"border:1px solid black;text-align:center;\"> 3,500</td></tr></table></div></div>", "topic": "CASH BOOK : MEANING AND TYPES OF CASH BOOK"}, {"id": "objective>Accounts>2016>28", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If an organization maintains a periodic stock system, the stock quantities are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">not considered in the updating process </div>", "<div style=\"font-family:Cambria;font-size:17px;\">updated at the beginning of the accounting year </div>", "<div style=\"font-family:Cambria;font-size:17px;\">updated continuously </div>", "<div style=\"font-family:Cambria;font-size:17px;\">updated at the end of the accounting year</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">In a periodic inventory system, the inventory is not updated continuously. Instead, it is updated at specific intervals, typically at the end of an accounting period. Therefore, the correct answer is 'updated at the end of the accounting year'.</div>", "topic": "STOCK VALUATION : MEANING OF STOCK VALUATION AND METHODS"}, {"id": "objective>Accounts>2016>29", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Clifford pays rent of ₦200 per month for premises. He paid ₦2,800 within the year. Compute the prepayment.</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦400</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦200</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦600</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦300</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Prepayment is an expense or income that is paid or received in advance of the period to which it relates. In this case, Clifford pays a monthly rent of ₦200 and he paid ₦2,800 within the year.  <br/>  <br/> This means he paid for 14 months  i.e (₦2,800 / ₦200).  <br/>  <br/> Since a year has 12 months, he has prepaid for 2 months.  <br/>  <br/> Therefore, the prepayment is 2 months x ₦200 <br/>  = ₦400.</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS"}, {"id": "objective>Accounts>2016>30", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following would be accounted for as an operating expense? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Purchase of land </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Repayment of bank loan </div>", "<div style=\"font-family:Cambria;font-size:17px;\">payment of rent </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Dividend to shareholder </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Operating expenses is the expenses incured in the cause of running a business operating expenses are expenses incurred for the purpose of smooth running of the business payment of rent is part of the expenses.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : TRADING ACTIVITIES"}, {"id": "objective>Accounts>2016>31", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> Cost of machinery 1/1/08 =  ₦200,000.  <br/> Depreciation at 10% reducing balance. <br/>  <br/> -  Determine the value of depreciation on 31/12/10 </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦18,000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦16,200 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦20,000 </div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦16,800 </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Calculate the annual depreciation rate: <br/> Annual Depreciation Rate = 10% = 0.10 <br/>  <br/> Calculate the depreciation for the first year (2008): <br/> Depreciation for 2008 = Cost of machinery x Annual Depreciation Rate <br/> Depreciation for 2008 = ₦200,000 x 0.10  <br/> = ₦20,000 <br/>  <br/> Calculate the book value at the end of the first year (2008): <br/> Book Value on 31/12/08 = Cost of machinery - Depreciation for 2008 <br/> Book Value on 31/12/08 = ₦200,000 - ₦20,000  <br/> = ₦180,000 <br/>  <br/> Calculate the depreciation for the second year (2009) based on the reduced book value: <br/> Depreciation for 2009 = Book Value on 31/12/08 x Annual Depreciation Rate <br/> Depreciation for 2009 = ₦180,000 x 0.10  <br/> = ₦18,000 <br/>  <br/> Calculate the book value at the end of the second year (2009): <br/> Book Value on 31/12/09 = Book Value on 31/12/08 - Depreciation for 2009 <br/> Book Value on 31/12/09 = ₦180,000 - ₦18,000  <br/> = ₦162,000 <br/>  <br/> Calculate the depreciation for the third year (2010) based on the reduced book value: <br/> Depreciation for 2010 = Book Value on 31/12/09 x Annual Depreciation Rate <br/> Depreciation for 2010 = ₦162,000 x 0.10  <br/> = ₦16,200 <br/>  <br/> So, the value of depreciation on 31/12/10 is ₦16,200.</div>", "topic": "DEPRECIATION OF FIXED ASSETS : METHODS OF DEPRECIATION"}, {"id": "objective>Accounts>2016>32", "question": "<div style=\"font-family:Cambria;font-size:17px;\">A credit balance in rent account will be in the balance sheet as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">capital </div>", "<div style=\"font-family:Cambria;font-size:17px;\">current asset </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fixed asset </div>", "<div style=\"font-family:Cambria;font-size:17px;\">current liability </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Credit balance in a rent ledger account will be shown in the balance sheet as current liabiity because it is an outstanding but otherwise,it is an asset.</div>", "topic": "THE FINAL ACCOUNTS OF A SOLE TRADER : BALANCE SHEET"}, {"id": "objective>Accounts>2016>33", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If a company values its stock in the period of rising prices using LIFO method, there is a tendency for it to </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">have a higher cost of goods sold </div>", "<div style=\"font-family:Cambria;font-size:17px;\">pay higher income tax </div>", "<div style=\"font-family:Cambria;font-size:17px;\">have a higher value for closing stock </div>", "<div style=\"font-family:Cambria;font-size:17px;\">have a higher gross profit </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">LIFO (Last In, First Out) is an inventory valuation method which assumes that the latest items purchased are the first ones to be sold. In a period of rising prices, using LIFO will result in a higher cost of goods sold because the latest purchased goods (which are sold first according to LIFO) are more expensive. This will reduce the company's net income and, consequently, its income tax liability.</div>", "topic": "STOCK VALUATION : MEANING OF STOCK VALUATION AND METHODS"}, {"id": "objective>Accounts>2016>34", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the source of income of a not-profit-making organization is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">return from sales </div>", "<div style=\"font-family:Cambria;font-size:17px;\">grant from the federal government </div>", "<div style=\"font-family:Cambria;font-size:17px;\">interest on loan to members </div>", "<div style=\"font-family:Cambria;font-size:17px;\">fines from erring members </div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">A not-for-profit organization does not operate for the purpose of making profit. Its main sources of income are donations, grants, and membership fees. Therefore, the correct answer is 'grant from the federal government'. This is because the federal government often provides grants to not-for-profit organizations to support their activities.</div>", "topic": "ACCOUNTS OF NON PROFIT MAKING ORGANISATION : INCOME AND EXPENDITURE ACCOUNTS"}, {"id": "objective>Accounts>2016>35", "question": "<div style=\"font-family:Cambria;font-size:17px;\">When using the first-in first-out method of valuation in a period of falling prices, profits are </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">divided equally </div>", "<div style=\"font-family:Cambria;font-size:17px;\">apportioned </div>", "<div style=\"font-family:Cambria;font-size:17px;\">understated </div>", "<div style=\"font-family:Cambria;font-size:17px;\">overstated </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The First-In, First-Out (FIFO) method is an inventory valuation method where the costs of the oldest inventory items are recorded as sold first. In a period of falling prices, using the FIFO method will result in lower cost of goods sold because the older, cheaper items are recorded as sold first. This leads to higher profits, hence the profits are understated.</div>", "topic": "STOCK VALUATION : MEANING OF STOCK VALUATION AND METHODS"}, {"id": "objective>Accounts>2016>36", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Where fresh issues of shares are made for cash, the accounting entries will be to debit </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">share premium account with premium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash account and credit appropriation account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash and credit share capital account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">current account </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Accounting entries for newly issued share that are made for cash will be  <br/>  DR: cash account  <br/>  CR: Share capital account.</div>", "topic": "ISSUES OF SHARES : MEANING AND CLASSES OF SHARES"}, {"id": "objective>Accounts>2016>37", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The objectives of preparing the branch mark-up account by the head office is to obtain the </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">gross profit of the branch </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cost of goods returned to the head office </div>", "<div style=\"font-family:Cambria;font-size:17px;\">expenditure profit of the branch </div>", "<div style=\"font-family:Cambria;font-size:17px;\">actual quantity of the unsold goods </div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Gross profit of the branch is usually the reason for the preparation of branch mark up account by the head office especially to ascertained the Gross - profit of the branch. <br/>  <br/> The branch mark-up or branch adjustment method ensure that a branch mark up account will be opened and the profit loading posted in order to determine the gross profit of the branch.</div>", "topic": "BRANCH ACCOUNTING : BRANCH ADJUSTMENT METHOD"}, {"id": "objective>Accounts>2016>38", "question": "<div style=\"font-family:Cambria;font-size:17px;\">July 1 - Started business with ₦ 10,500  <br/> July 31 - Paid Agromachinex ₦ 6,000 owing to them  <br/> The double entry for 31 July would be </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">debit equipment and credit Agromachinex </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit cash and debit purchases </div>", "<div style=\"font-family:Cambria;font-size:17px;\">credit capital and debit cash </div>", "<div style=\"font-family:Cambria;font-size:17px;\">debit Agromachinex and credit cash </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The double entry system in accounting means that every business transaction will involve two accounts (or more). For example, when a company borrows money from its bank, the company's Cash account will increase and its liability account Loans Payable will increase. In this case, the business paid Agromachinex, which means cash (an asset) decreased. In double entry bookkeeping, a decrease in an asset is credited. Therefore, we credit cash. The business also settled a liability (amount owing to Agromachinex), and a decrease in a liability is debited. Therefore, we debit Agromachinex.</div>", "topic": "PRINCIPLE OF DOUBLE ENTRY : CASH AND CREDIT TRANSACTIONS"}, {"id": "objective>Accounts>2016>39", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The concept referring to profit recognition when goods are sold is </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">going concern </div>", "<div style=\"font-family:Cambria;font-size:17px;\">matching </div>", "<div style=\"font-family:Cambria;font-size:17px;\">realization </div>", "<div style=\"font-family:Cambria;font-size:17px;\">periodicity </div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The realization principle is the concept that revenue can only be recognized once the underlying goods or services associated with the revenue have been delivered or rendered, respectively.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS"}, {"id": "objective>Accounts>2016>40", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Given: <br/> I. Payment of debts owed to creditors <br/> II. Payment of any loan  <br/> III. Repayment of capital contributed  <br/> IV. Sharing of surplus among the partners on an agreed term.  <br/> According to the partnership Act, when partnership is dissolved, payment should be prioritized as </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">II, III, IV and I </div>", "<div style=\"font-family:Cambria;font-size:17px;\">IV, I, II and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I, II, III and  IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">III, IV, I and II</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">According to the Partnership Act, when a partnership is dissolved, the payment should be prioritized as follows: Payment of debts owed to creditors (I), Payment of any loan (II), Repayment of capital contributed (III), and Sharing of surplus among the partners on an agreed term (IV). This is because the law requires that the partnership's external liabilities be settled first before the internal liabilities and distributions.</div>", "topic": "DISSOLUTION OF PARTNERSHIP ACCOUNT : INTRODUCTION AND RULES FOR DISTRIBUTING OF ASSSETS"}, {"id": "objective>Accounts>2016>41", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Which of the following is the capital reserve of a company? </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Retained profit </div>", "<div style=\"font-family:Cambria;font-size:17px;\">loss on forfeited shares </div>", "<div style=\"font-family:Cambria;font-size:17px;\">share premium </div>", "<div style=\"font-family:Cambria;font-size:17px;\">Accumulated depreciation</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The capital reserve of a company is an account on the company's balance sheet that is dedicated to money reserved for long-term projects or large, anticipated expenses. This can include the share premium, which is the amount received from the issue of shares above their face value. The other options do not represent capital reserves. Retained profit is a part of earned reserves, loss on forfeited shares is a loss, not a reserve, and accumulated depreciation is a contra asset account, not a reserve.</div>", "topic": "RESERVES AND PROVISIONS : MEANING OF RESERVE AND PROVISIONS"}, {"id": "objective>Accounts>2016>42", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The details of the share capital which a company is authorized to issue is contained in </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">its Article of Association </div>", "<div style=\"font-family:Cambria;font-size:17px;\">the Companies and Allied Matters Act </div>", "<div style=\"font-family:Cambria;font-size:17px;\">its share capital certificate </div>", "<div style=\"font-family:Cambria;font-size:17px;\">its Memorandum of Association </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Details of share that can be issued by the company must be contained in the Memorandum of Association of the company. Memorandum of Association is a document that contains terms and conditions that governs the overall business of a company and how shareholders relate.</div>", "topic": "COMPANY ACCOUNT : FORMATION OF COMPANY"}, {"id": "objective>Accounts>2016>43", "question": "<div style=\"font-family:Cambria;font-size:17px;\">Investors are interested in accounting information to determine the organization's </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">profitability ratio </div>", "<div style=\"font-family:Cambria;font-size:17px;\">liquidity ratio</div>", "<div style=\"font-family:Cambria;font-size:17px;\">current ratio </div>", "<div style=\"font-family:Cambria;font-size:17px;\">solvency level </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Investors are interested in accounting information to determine the organization's solvency level. Solvency refers to the ability of a company to meet its long-term financial obligations. Investors need to know this to assess the risk associated with their investment. While profitability, liquidity, and current ratios are also important, they are aspects of a company's financial health, not the overall solvency level.</div>", "topic": "ACCOUNTING RATIO (2) : PROFITABILITY, LIQUIDITY AND INVESTMENT RATIO"}, {"id": "objective>Accounts>2016>44", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In order to make the cash book balance equal to the bank statement, it is usual to add</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Uncredited cheques</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Direct payments by bank</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Bank charges</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Unpresented cheques</div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">An unpresented cheque is a cheque that was written but has not yet been paid by the bank on which it is drawn. An unpresented cheque is also referred to as an outstanding cheque or a cheque that has not yet cleared the bank.</div>", "topic": "BANK RECONCILIATION STATEMENT : INTRODUCTION AND REASONS FOR DISAGREENMENT BETWEEN CASH BOOK & BANK STATEMENT"}, {"id": "objective>Accounts>2016>45", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The body constitutionally charge with the accounts of the Federation and other Assembly is the</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">Public Accounts Committee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Public Audit Committee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">Internal Audit Committee</div>", "<div style=\"font-family:Cambria;font-size:17px;\">External Audit Committee</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The Public Accounts Committee examines the value for money of Government projects, programmes and service delivery. </div>", "topic": "PUBLIC SECTOR ACCOUNTING : INTRODUCTION AND USERS OF GOVERNMENT ACCOUNTING"}, {"id": "objective>Accounts>2016>46", "question": "<div style=\"font-family:Cambria;font-size:17px;\">If liabilities amounted to ₦12,045, other assets ₦36,800 and equity ₦26,896, the cash at hand would be</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">₦2,241</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,214</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,141</div>", "<div style=\"font-family:Cambria;font-size:17px;\">₦2,114</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\"> Cash at hand = Liabilities + Equity - Other Assets <br/>  = ₦ (12,045 + 26,896 - 36,800)  <br/> = ₦2,141</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING EQUATION"}, {"id": "objective>Accounts>2016>47", "question": "<div style=\"font-family:Cambria;font-size:17px;\">The channel through which all government borrowing and domestic lending transactions pass is called</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">special trust fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">agency fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">national loan fund</div>", "<div style=\"font-family:Cambria;font-size:17px;\">contingency fund</div>"], "answer": 2, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">The National Loan Fund is the channel through which all government borrowing and domestic lending transactions pass.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : SOURCES AND CLASSIFICATION OF GOVERNMENT REVENUE"}, {"id": "objective>Accounts>2016>48", "question": "<div style=\"font-family:Cambria;font-size:17px;\">In an incomplete record, the preparation of bank reconciliation ensures that</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">all cash takings are banked</div>", "<div style=\"font-family:Cambria;font-size:17px;\">the cash book is correct</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there are no overdraft</div>", "<div style=\"font-family:Cambria;font-size:17px;\">there are no hidden loan</div>"], "answer": 1, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Incomplete record is a system of accounting where most records are not recorded. This will affect the cash book and will be counted when bank reconciliation is prepared.</div>", "topic": "SINGLE ENTRY AND INCOMPLETE RECORDS : INTRODUCTION AND ADVANTAGES"}, {"id": "objective>Accounts>2016>49", "question": "<div style=\"font-family:Cambria;font-size:17px;\">I. Fixtures account  <br/>  II. Machinery account   <br/>  III. Wages account   <br/> IV. Rent account   <br/>  Which of the above are nominal accounts?</div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">III and IV</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and II</div>", "<div style=\"font-family:Cambria;font-size:17px;\">I and III</div>", "<div style=\"font-family:Cambria;font-size:17px;\">II and III</div>"], "answer": 0, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Nominal accounts are accounts of intangible assets, expenses and revenue accounts. Wages and rent accounts are expenses accounts.</div>", "topic": "INTRODUCTION TO ACCOUNTING : ACCOUNTING CONCEPTS AND CONVENTIONS"}, {"id": "objective>Accounts>2016>50", "question": "<div style=\"font-family:Cambria;font-size:17px;\">One of the major difference between government accounting and commercial accounting is that, the former uses </div>", "options": ["<div style=\"font-family:Cambria;font-size:17px;\">profit and loss account while the later uses income and expenditure account </div>", "<div style=\"font-family:Cambria;font-size:17px;\">accounting standard while the latter uses accounting ethics </div>", "<div style=\"font-family:Cambria;font-size:17px;\">cash basis while the latter uses accrual basis </div>", "<div style=\"font-family:Cambria;font-size:17px;\">accounting ethics while the latter uses accounting standard </div>"], "answer": 3, "explanation": "<div style=\"font-family:Cambria;font-size:17px;\">Commercial accounting is used to record transactions in commercial organizations while Government accounting in no way is related to show profit or loss of the government office. <br/>  <br/> -  .Commercial accounting is concerned with profit or loss of the concern. while Government accounting is normally maintained in cash basis. <br/>  <br/> -   Government accounting is maintained strictly following the provisions made in finance act and rules.It is rigid while Commercial accounting is not necessarily bound to follow the finance act and rules.It is guided by its internal rules.It is liberal in practice.</div>", "topic": "PUBLIC SECTOR ACCOUNTING : PURPOSE AND DIFFERENCE BETWEEN GOVERNMENT AND COMMERCIAL ACCOUNTING"}];
